Similar to #482 
```
module unp_assign;
  wire [3:0] a, b;
  wire [7:0] c;
  wire [3:0] d [1:0];

  assign a = 4'ha;
  assign b = 4'hb;
  assign c = {a, b}; // packed is OK

  // 1800-2012 LRM 10.10.1 allows either of the following (both fail)
  assign d = '{a, b}; // array literal
//  assign d = {a, b}; // unpacked array concatenation

//  iverilog workaround: separate assignments are OK
//  assign d[1] = a;
//  assign d[0] = b;

  initial #1 $display("%h %h%h", c, d[1], d[0]);
endmodule
```

